+        assert_eq!(screen.focus, Focus::Replace);
+    }
+
+    #[test]
+    fn escape_closes_search() {
+        let mut screen = AdvancedTextEditor::new();
+        screen.update(&ctrl_press(KeyCode::Char('f')));
